import random
from Crypto.Util.number import getPrime, bytes_to_long


def generate_challenge():
    bits = 1024
    p = getPrime(bits)
    q = getPrime(bits)
    N = p * q

    hidden_p_bits = 502
    p_high = p >> hidden_p_bits

    a = random.randint(2, p - 1)
    c = random.randint(2, p - 1)

    flag = flag.ljust(64, b'\x00')
    seed = bytes_to_long(flag)
    assert seed < p

    def lcg(state):
        return a * ( state - c) % p

    states = [seed]
    for _ in range(5):
        states.append(lcg(states[-1]))

    k = 256
    outputs = [s >> k for s in states]

    print("===== The Coppersmith & LLL Forge =====")
    print(f"N = {N}")
    print(f"p_high = {p_high}")
    print(f"a = {a}")
    print(f"c = {c}")
    print(f"outputs = {outputs}")


if __name__ == "__main__":
    generate_challenge()

